#include<bits/stdc++.h>
using namespace std;
const int N=100005;
int n,m,a[N],cnt[25],cnt2[N][25],dp[1<<20];
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        cnt[a[i]]++;
        for(int j=1;j<=m;j++) cnt2[i][j]=cnt2[i-1][j];
        cnt2[i][a[i]]++;
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
    for(int i=1;i<(1<<m);i++)
    {
        int len=0;
        for(int j=1;j<=m;j++)
        {
            if((i>>(j-1))%2) len+=cnt[j];
        }
        for(int j=1;j<=m;j++)
        {
            if((i>>(j-1))%2) dp[i]=min(dp[i],dp[i^(1<<(j-1))]+cnt[j]-cnt2[len][j]+cnt2[len-cnt[j]][j]);
        }
    }
    cout<<dp[(1<<m)-1];
    return 0;
}
